module RefModule(input clk, input reset, input [3:0] in, output reg p);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
	if(reset)
		p <= 0;
	else begin
		if(in == 4'b0010)
			p <= 1;
		else
			p <= 0;
	end
end

endmodule
